import java.util.PriorityQueue

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val numNodes = n.toInt()
    val graph = Array(numNodes) { mutableListOf<Pair<Int, Long>>() }
    val reverseGraph = Array(numNodes) { mutableListOf<Pair<Int, Long>>() }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        graph[u].add(v to w)
        reverseGraph[v].add(u to w)
    }

    val dist = Array(numNodes) { LongArray(2) { Long.MAX_VALUE } }
    dist[0][0] = 0

    val heap = PriorityQueue<Pair<Long, Pair<Int, Int>>>(compareBy { it.first })
    heap.add(0L to (0 to 0))

    while (heap.isNotEmpty()) {
        val (currentDist, state) = heap.poll()
        val (u, used) = state

        if (currentDist > dist[u][used]) continue

        if (u == numNodes - 1) {
            return currentDist
        }

        for ((v, w) in graph[u]) {
            val newDist = currentDist + w
            if (newDist < dist[v][used]) {
                dist[v][used] = newDist
                heap.add(newDist to (v to used))
            }
        }

        if (used == 0) {
            for ((v, w) in reverseGraph[u]) {
                val newDist = currentDist + 2 * w
                if (newDist < dist[v][1]) {
                    dist[v][1] = newDist
                    heap.add(newDist to (v to 1))
                }
            }
        }
    }

    val result = minOf(dist[numNodes - 1][0], dist[numNodes - 1][1])
    return if (result != Long.MAX_VALUE) result else -1
}
